parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "estilo_detectado": {
      "type": "string",
      "description": "ej: elegante, rústico, moderno, temático, bohemio"
    },
    "colores_predominantes": {
      "type": "array",
      "items": {
        "type": "string"
      }
    },
    "tipo_evento_sugerido": {
      "type": "string",
      "description": "ej: matrimonio, cumpleaños, corporativo"
    },
    "complejidad_estimada": {
      "type": "string",
      "enum": [
        "baja",
        "media",
        "alta"
      ]
    },
    "descripcion": {
      "type": "string",
      "description": "resumen breve de lo interpretado para responder al cliente"
    }
  },
  "required": [
    "estilo_detectado",
    "colores_predominantes",
    "tipo_evento_sugerido",
    "complejidad_estimada",
    "descripcion"
  ]
}
